#!/usr/bin/env node

// src/index.ts
import { Command } from "commander";

// src/commands/init.ts
import fs2 from "fs-extra";
import path2 from "path";
import pc from "picocolors";

// src/config.ts
import fs from "fs-extra";
import path from "path";
var CONFIG_FILE = "forge.config.json";
async function readConfig() {
  const configPath = path.join(process.cwd(), CONFIG_FILE);
  if (!await fs.pathExists(configPath)) return null;
  return fs.readJson(configPath);
}
async function writeConfig(config) {
  const configPath = path.join(process.cwd(), CONFIG_FILE);
  await fs.writeJson(configPath, config, { spaces: 2 });
}
function createDefaultConfig() {
  return {
    version: "0.1.0",
    output: "components/forge",
    components: {}
  };
}

// src/commands/init.ts
async function runInit() {
  console.log(pc.bold("\n  forge-ui init\n"));
  const existing = await readConfig();
  if (existing) {
    console.log(pc.yellow("  forge.config.json already exists \u2014 skipping."));
    console.log(pc.dim("  Run npx forge-ui add <component> to add components.\n"));
    return;
  }
  const config = createDefaultConfig();
  await writeConfig(config);
  const outputDir = path2.join(process.cwd(), config.output);
  await fs2.ensureDir(outputDir);
  const tokensPath = path2.join(outputDir, "forge-tokens.css");
  const tokens = `/* forge-tokens.css \u2014 generated by forge-ui CLI */
/* Import this in your root layout: import '@/components/forge/forge-tokens.css' */
/* Override any token to retheme your entire installation. */

:root {
  /* Backgrounds */
  --forge-bg:     #09090b;
  --forge-bg2:    #0f0f12;
  --forge-bg3:    #141418;

  /* Text */
  --forge-text:   #f0ede8;
  --forge-muted:  rgba(240, 237, 232, 0.38);
  --forge-hint:   rgba(240, 237, 232, 0.15);

  /* Spectrum palette */
  --forge-purple: #7F77DD;
  --forge-blue:   #378ADD;
  --forge-red:    #e24b4a;
  --forge-amber:  #EF9F27;
  --forge-teal:   #1D9E75;
  --forge-pink:   #D4537E;

  /* Typography */
  --forge-font:   'Inter', sans-serif;
  --forge-mono:   'DM Mono', monospace;
}
`;
  await fs2.writeFile(tokensPath, tokens, "utf8");
  console.log(pc.green("  \u2713") + " forge.config.json");
  console.log(pc.green("  \u2713") + ` ${config.output}/forge-tokens.css`);
  console.log(pc.dim("\n  Next: import the tokens in your root layout"));
  console.log(pc.cyan(`  import '@/components/forge/forge-tokens.css'
`));
}

